export default {
	data() {
		return {
			list: [],//公司列表
			tabCur: 0,
			mainCur: 0,
			verticalNavTop: 0,
			load: true,
			bigarea:'',//大区
			bigareaIndex:0,//大区索引
			bigareaId:'',//大区id
			c_id:'',//公司id
			projectList:'',//楼盘
			activeIndex:-1
		};
	},
	onLoad() {
		this.getBigareacustomapi();
	},
	onReady() {
		uni.hideLoading()
	},
	
	methods: {
		buildDetail(item,index,pname){
			this.activeIndex = index;
			if(item.id){
				uni.navigateTo({
					url:'/pages/change-tower/change-tower?bid='+item.id+'&pname='+pname+'&bname='+item.name
				})
			}
		},
		chooseBigarea(item,index){
			this.bigareaIndex =  index;
			this.bigareaId = item.id;
			if(this.bigareaId){
				this.getCompanyList();
			}
		},
		TabSelect(item,e) {
			this.tabCur = e;
			this.mainCur = e;
			this.verticalNavTop = (e - 1) * 50;
			this.c_id = item.c_id;
			if(this.c_id){
				this.getHouseList();	
			}
		},
		VerticalMain(e) {



			let that = this;
			let tabHeight = 0;
			if (this.load) {
				for (let i = 0; i < this.list.length; i++) {
					let view = uni.createSelectorQuery().select("#main-" + this.list[i].id);
					view.fields({
						size: true
					}, data => {
						this.list[i].top = tabHeight;
						tabHeight = tabHeight + data.height;
						this.list[i].bottom = tabHeight;
					}).exec();
				}
				this.load = false
			}
			let scrollTop = e.detail.scrollTop + 10;
			for (let i = 0; i < this.list.length; i++) {
				if (scrollTop > this.list[i].top && scrollTop < this.list[i].bottom) {
					this.verticalNavTop = (this.list[i].id - 1) * 50
					this.tabCur = this.list[i].id
					console.log(scrollTop)
					return false
				}
			}
		},
		//根据权限获取大区和大区下的项目
		getBigareacustomapi(){
			uni.showLoading({
				title: '正在加载数据...'
			});
			this.$api.customGetbigareacustomapi({},res =>{
				this.bigarea =  res.data;
				if(this.bigarea){
					this.bigareaId = this.bigarea[0].id;
					this.getCompanyList();
				}
			})
		},
		//公司列表
		getCompanyList(){
			let data ={
				id:this.bigareaId
			}
			uni.showLoading({
				title: '正在加载数据...'
			});
			this.$api.customGetcompanylistcustomapi(data,res =>{
				this.list = res.data;
				if(this.list){
					this.c_id = this.list[0].c_id;
					this.getHouseList();
				}
			})
		},
		//房源列表
		getHouseList(){
			uni.showLoading({
				title:'正在加载数据...'
			})
			this.$api.getProjectbuildingcustomapi({cid:this.c_id},res =>{
				this.projectList = res.data;
			})
		}
	},
}
